import os
import numpy as np
import pandas as pd
import matplotlib.pyplot as plt

OUT = "/home/owais-saeed/python/ML/EPL/"
FIG = os.path.join(OUT, "figures")
os.makedirs(FIG, exist_ok=True)

models = ["KNN", "Logistic Regression", "Naive Bayes", "SVM", "Neural Network"]
class_labels = ["Away Win", "Draw", "Home Win"]

# Read model result files generated by epl.py
global_df = pd.read_csv(os.path.join(OUT, "results_global_3way.csv"))
global_df = global_df[global_df["Classifier"].isin(models)].copy()
per_season = pd.read_csv(os.path.join(OUT, "results_per_season_3way.csv"))
f1_df = pd.read_csv(os.path.join(OUT, "results_per_class_f1.csv"))

# 01 Test Accuracy
plt.figure(figsize=(12, 6))
plt.barh(global_df["Classifier"], global_df["Accuracy"])
plt.axvline(1/3, linestyle="--", linewidth=1.5, label="Random baseline (33%)")
plt.xlim(0, 1)
plt.xlabel("Accuracy")
plt.title("Test Accuracy", fontsize=18, fontweight="bold")
plt.legend()
plt.gca().invert_yaxis()
for i, v in enumerate(global_df["Accuracy"]):
    plt.text(v + 0.01, i, f"{v:.3f}", va="center", fontweight="bold")
plt.tight_layout()
plt.savefig(os.path.join(FIG, "01_test_accuracy.png"), dpi=300, bbox_inches="tight")
plt.close()

# Confusion matrices
for model in models:
    fname = f"confusion_matrix_{model.lower().replace(' ', '_')}.csv"
    cm = pd.read_csv(os.path.join(OUT, fname), index_col=0).values
    row_sum = cm.sum(axis=1, keepdims=True)
    cm_pct = cm / row_sum * 100

    plt.figure(figsize=(9, 8))
    im = plt.imshow(cm_pct, cmap="Blues")
    plt.colorbar(im)
    acc = float(global_df.loc[global_df["Classifier"] == model, "Accuracy"].iloc[0])
    plt.title(f"{model} Confusion Matrix\nAccuracy = {acc:.3f}", fontsize=22, fontweight="bold")
    plt.xlabel("Predicted", fontsize=16)
    plt.ylabel("Actual", fontsize=16)
    plt.xticks(range(3), class_labels, rotation=35, ha="right", fontsize=14)
    plt.yticks(range(3), class_labels, fontsize=14)
    for r in range(3):
        for c in range(3):
            val = cm_pct[r, c]
            color = "white" if val > 50 else "black"
            plt.text(c, r, f"{val:.1f}%", ha="center", va="center", fontsize=16, fontweight="bold", color=color)
    plt.tight_layout()
    safe = model.lower().replace(" ", "_")
    plt.savefig(os.path.join(FIG, f"02_confusion_matrix_{safe}.png"), dpi=300, bbox_inches="tight")
    plt.close()

# 03 Per-class F1 heatmap
heat = f1_df[class_labels].values
plt.figure(figsize=(9, 8))
im = plt.imshow(heat, cmap="YlGn")
plt.colorbar(im)
plt.title("Per-Class F1 Score", fontsize=24, fontweight="bold")
plt.xticks(range(3), class_labels, fontsize=15)
plt.yticks(range(len(f1_df)), f1_df["Classifier"], fontsize=15)
for r in range(heat.shape[0]):
    for c in range(heat.shape[1]):
        plt.text(c, r, f"{heat[r, c]:.3f}", ha="center", va="center", fontsize=16, fontweight="bold")
plt.tight_layout()
plt.savefig(os.path.join(FIG, "03_per_class_f1.png"), dpi=300, bbox_inches="tight")
plt.close()

# 04 Precision / Recall / F1 Macro
x = np.arange(len(global_df))
w = 0.25
plt.figure(figsize=(14, 6))
plt.bar(x - w, global_df["Precision"], width=w, label="Precision")
plt.bar(x, global_df["Recall"], width=w, label="Recall")
plt.bar(x + w, global_df["MacroF1"], width=w, label="F1-score")
plt.xticks(x, global_df["Classifier"], rotation=25, ha="right")
plt.ylim(0, 1)
plt.ylabel("Score")
plt.title("Precision / Recall / F1 (Macro Average)", fontsize=18, fontweight="bold")
plt.legend()
plt.tight_layout()
plt.savefig(os.path.join(FIG, "04_precision_recall_f1_macro.png"), dpi=300, bbox_inches="tight")
plt.close()

# 05 Result distribution using known test counts from the experiment output
counts = pd.Series({"Home Win": 517, "Away Win": 333, "Draw": 290})
plt.figure(figsize=(8, 8))
plt.pie(counts.values, labels=counts.index, autopct="%1.1f%%", startangle=90)
plt.title(f"Result Distribution\n({counts.sum():,} matches)", fontsize=20, fontweight="bold")
plt.tight_layout()
plt.savefig(os.path.join(FIG, "05_result_distribution.png"), dpi=300, bbox_inches="tight")
plt.close()

# 06 Per-season accuracy
plt.figure(figsize=(13, 5))
plt.plot(per_season["Season"], per_season["Best acc"], marker="o", label="Best Model Accuracy")
plt.plot(per_season["Season"], per_season["Mean acc(5)"], marker="o", label="Mean Accuracy of 5 Models")
plt.ylim(0, 1)
plt.xlabel("Season")
plt.ylabel("Accuracy")
plt.title("Per-Season Model Performance", fontsize=18, fontweight="bold")
plt.grid(True, linestyle="--", alpha=0.4)
plt.legend()
plt.tight_layout()
plt.savefig(os.path.join(FIG, "06_per_season_accuracy.png"), dpi=300, bbox_inches="tight")
plt.close()

print("Separate PNG figures saved in:", FIG)
